import{_ as s,o as i,c as e,ai as n}from"./chunks/framework.CsYGeNYI.js";const k=JSON.parse('{"title":"macOS 上的 Gateway 网关","description":"","frontmatter":{"read_when":["打包 OpenSoul.app","调试 macOS Gateway 网关 launchd 服务","为 macOS 安装 Gateway 网关 CLI"],"summary":"macOS 上的 Gateway 网关运行时（外部 launchd 服务）","title":"macOS 上的 Gateway 网关","x-i18n":{"generated_at":"2026-02-03T07:52:30Z","model":"claude-opus-4-5","provider":"pi","source_hash":"4a3e963d13060b123538005439213e786e76127b370a6c834d85a369e4626fe5","source_path":"platforms/mac/bundled-gateway.md","workflow":15}},"headers":[],"relativePath":"zh-CN/platforms/mac/bundled-gateway.md","filePath":"zh-CN/platforms/mac/bundled-gateway.md","lastUpdated":1771906665000}'),l={name:"zh-CN/platforms/mac/bundled-gateway.md"};function t(p,a,h,d,r,o){return i(),e("div",null,[...a[0]||(a[0]=[n(`<h1 id="macos-上的-gateway-网关-外部-launchd" tabindex="-1"><a class="header-anchor" href="#macos-上的-gateway-网关-外部-launchd">#</a> macOS 上的 Gateway 网关（外部 launchd）</h1><p>OpenSoul.app 不再捆绑 Node/Bun 或 Gateway 网关运行时。macOS 应用期望有一个<strong>外部</strong>的 <code>opensoul</code> CLI 安装，不会将 Gateway 网关作为子进程启动，而是管理一个每用户的 launchd 服务来保持 Gateway 网关运行（或者如果已有本地 Gateway 网关正在运行，则连接到现有的）。</p><h2 id="安装-cli-本地模式必需" tabindex="-1"><a class="header-anchor" href="#安装-cli-本地模式必需">#</a> 安装 CLI（本地模式必需）</h2><p>你需要在 Mac 上安装 Node 22+，然后全局安装 <code>opensoul</code>：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -g</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> opensoul@</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">versio</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">n</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>macOS 应用的<strong>安装 CLI</strong>按钮通过 npm/pnpm 运行相同的流程（不推荐使用 bun 作为 Gateway 网关运行时）。</p><h2 id="launchd-gateway-网关作为-launchagent" tabindex="-1"><a class="header-anchor" href="#launchd-gateway-网关作为-launchagent">#</a> Launchd（Gateway 网关作为 LaunchAgent）</h2><p>标签：</p><ul><li><code>ai.opensoul.gateway</code>（或 <code>ai.opensoul.&lt;profile&gt;</code>；旧版 <code>com.opensoul.*</code> 可能仍然存在）</li></ul><p>Plist 位置（每用户）：</p><ul><li><code>~/Library/LaunchAgents/ai.opensoul.gateway.plist</code> （或 <code>~/Library/LaunchAgents/ai.opensoul.&lt;profile&gt;.plist</code>）</li></ul><p>管理者：</p><ul><li>macOS 应用在本地模式下拥有 LaunchAgent 的安装/更新权限。</li><li>CLI 也可以安装它：<code>opensoul gateway install</code>。</li></ul><p>行为：</p><ul><li>&quot;OpenSoul Active&quot;启用/禁用 LaunchAgent。</li><li>应用退出<strong>不会</strong>停止 Gateway 网关（launchd 保持其存活）。</li><li>如果 Gateway 网关已经在配置的端口上运行，应用会连接到它而不是启动新的。</li></ul><p>日志：</p><ul><li>launchd stdout/err：<code>/tmp/opensoul/opensoul-gateway.log</code></li></ul><h2 id="版本兼容性" tabindex="-1"><a class="header-anchor" href="#版本兼容性">#</a> 版本兼容性</h2><p>macOS 应用会检查 Gateway 网关版本与其自身版本是否匹配。如果不兼容，请更新全局 CLI 以匹配应用版本。</p><h2 id="冒烟测试" tabindex="-1"><a class="header-anchor" href="#冒烟测试">#</a> 冒烟测试</h2><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opensoul</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --version</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">OPENSOUL_SKIP_CHANNELS</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">1</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> \\</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">OPENSOUL_SKIP_CANVAS_HOST=1 </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">\\</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">opensoul </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">gateway</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --port</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 18999</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --bind</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> loopback</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>然后：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opensoul</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gateway</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> call</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> health</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --url</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ws://127.0.0.1:18999</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --timeout</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 3000</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div>`,23)])])}const u=s(l,[["render",t]]);export{k as __pageData,u as default};
